/**
 * RulesGenerator — .mdc 文件生成器
 *
 * 生成 Cursor Rules 格式的 .mdc 文件到 .cursor/rules/ 目录：
 *   - Channel A: alembic-project-rules.mdc (alwaysApply: true)
 *   - Channel B: alembic-patterns-{topic}.mdc (alwaysApply: false)
 */
import fs from 'node:fs';
import path from 'node:path';
import { getCursorRulesDir, getCursorRulesRelativePath } from '../../shared/ide-paths.js';
import { BUDGET, estimateTokens } from './TokenBudget.js';
export class RulesGenerator {
    projectName;
    projectRoot;
    rulesDir;
    wz;
    /**
     * @param projectRoot 用户项目根目录
     * @param projectName 项目名称（用于 description/标题）
     * @param [wz] WriteZone 实例（可选，提供后写入操作走 WriteZone 管控）
     */
    constructor(projectRoot, projectName = 'Project', wz) {
        this.projectRoot = projectRoot;
        this.projectName = projectName;
        this.rulesDir = getCursorRulesDir(projectRoot);
        this.wz = wz ?? null;
    }
    /**
     * Channel A — 写入 Always-On Rules 文件
     *
     * @param ruleLines 一行式规则列表 (来自 KnowledgeCompressor.compressToRuleLine)
     * @returns }
     */
    writeAlwaysOnRules(ruleLines) {
        this._ensureDir();
        // Token 预算控制
        const kept = [];
        let tokens = 0;
        const headerFooterBudget = 100;
        const ruleBudget = BUDGET.CHANNEL_A_MAX - headerFooterBudget;
        for (const line of ruleLines) {
            const lineTokens = estimateTokens(line);
            if (tokens + lineTokens <= ruleBudget && kept.length < BUDGET.CHANNEL_A_MAX_RULES) {
                kept.push(line);
                tokens += lineTokens;
            }
        }
        const content = this._renderChannelA(kept);
        const filePath = path.join(this.rulesDir, 'alembic-project-rules.mdc');
        if (this.wz) {
            this.wz.writeFile(this.wz.project(getCursorRulesRelativePath('alembic-project-rules.mdc')), content);
        }
        else {
            fs.writeFileSync(filePath, content, 'utf8');
        }
        return {
            filePath,
            tokensUsed: estimateTokens(content),
            rulesCount: kept.length,
        };
    }
    /**
     * Channel B — 写入 Smart Rules 文件（按主题）
     *
     * @param topic 主题名 (networking, ui, data, architecture, conventions, general)
     * @param compressedContent 格式化后的 When/Do/Don't Markdown 内容
     * @param description Agent 关联性判断用 description
     * @returns }
     */
    writeSmartRules(topic, compressedContent, description) {
        this._ensureDir();
        // Token 预算控制
        let body = compressedContent;
        const totalTokens = estimateTokens(body) + estimateTokens(description) + 50;
        if (totalTokens > BUDGET.CHANNEL_B_MAX_PER_FILE) {
            // 截断尾部
            const lines = body.split('\n');
            const truncated = [];
            let used = estimateTokens(description) + 50;
            for (const line of lines) {
                used += estimateTokens(`${line}\n`);
                if (used <= BUDGET.CHANNEL_B_MAX_PER_FILE) {
                    truncated.push(line);
                }
            }
            body = truncated.join('\n');
        }
        const content = this._renderChannelB(topic, body, description);
        const fileName = `alembic-patterns-${topic}.mdc`;
        const filePath = path.join(this.rulesDir, fileName);
        if (this.wz) {
            this.wz.writeFile(this.wz.project(getCursorRulesRelativePath(fileName)), content);
        }
        else {
            fs.writeFileSync(filePath, content, 'utf8');
        }
        return {
            filePath,
            tokensUsed: estimateTokens(content),
        };
    }
    /**
     * 清理旧的动态生成文件
     * 保留静态模板文件（alembic-conventions.mdc, alembic-skills.mdc）
     */
    cleanDynamicFiles() {
        if (!fs.existsSync(this.rulesDir)) {
            return;
        }
        const dynamicPrefixes = ['alembic-project-rules', 'alembic-patterns-'];
        const files = fs.readdirSync(this.rulesDir);
        for (const file of files) {
            if (dynamicPrefixes.some((p) => file.startsWith(p))) {
                const filePath = path.join(this.rulesDir, file);
                try {
                    if (this.wz) {
                        this.wz.remove(this.wz.project(getCursorRulesRelativePath(file)));
                    }
                    else {
                        fs.unlinkSync(filePath);
                    }
                }
                catch {
                    /* ignore */
                }
            }
        }
    }
    // ─── 渲染方法 ───────────────────────────────────────
    _renderChannelA(ruleLines) {
        const desc = `${this.projectName} mandatory rules — coding constraints that must never be violated. Auto-generated by Alembic.`;
        const lines = [
            '---',
            `description: "${desc}"`,
            'alwaysApply: true',
            '---',
            '',
            `# ${this.projectName} — Mandatory Rules`,
            '',
            ...ruleLines,
            '',
            'For detailed patterns and recipes, Alembic MCP tools are available:',
            '- `alembic_search({ query })` — search knowledge base (auto mode: BM25 + semantic)',
            '- `alembic_search({ query, mode: "context" })` — context-aware search with history',
        ];
        return `${lines.join('\n')}\n`;
    }
    _renderChannelB(topic, body, description) {
        const topicLabel = topic.charAt(0).toUpperCase() + topic.slice(1);
        const lines = [
            '---',
            `description: "${description}"`,
            'alwaysApply: false',
            '---',
            '',
            `# ${topicLabel} Patterns`,
            '',
            body,
            '',
            `For full code examples: \`alembic_search("${topic}")\``,
        ];
        return `${lines.join('\n')}\n`;
    }
    /**
     * Baseline Rules — 零知识库时写入基础引导文件
     * 告知 Agent 可用的 MCP 工具和推荐工作流
     */
    writeBaselineRules() {
        this._ensureDir();
        const content = this._renderBaseline();
        const filePath = path.join(this.rulesDir, 'alembic-project-rules.mdc');
        if (this.wz) {
            this.wz.writeFile(this.wz.project(getCursorRulesRelativePath('alembic-project-rules.mdc')), content);
        }
        else {
            fs.writeFileSync(filePath, content, 'utf8');
        }
        return {
            filePath,
            tokensUsed: estimateTokens(content),
            rulesCount: 0,
        };
    }
    _renderBaseline() {
        const lines = [
            '---',
            `description: "${this.projectName} — Alembic baseline guidance. Available MCP tools and recommended workflows."`,
            'alwaysApply: true',
            '---',
            '',
            `# ${this.projectName} — Alembic Baseline`,
            '',
            'This project has Alembic enabled but no knowledge entries yet.',
            'Use the following MCP tools to build and query the knowledge base:',
            '',
            '## Available MCP Tools',
            '',
            '- `alembic_bootstrap` — Cold-start: analyze the project and generate initial knowledge entries',
            '- `alembic_search({ query })` — Search knowledge base (BM25 + semantic)',
            '- `alembic_knowledge({ action: "submit" })` — Submit a knowledge candidate (strict validation)',
            '- `alembic_guard` — Run compliance review on current changes',
            '- `alembic_task` — Task & decision management (prime/create/claim/close/record_decision)',
            '- `alembic_panorama` — Project panorama (overview/module/gaps/health)',
            '',
            '## Recommended First Steps',
            '',
            '1. Run `alembic_bootstrap` to analyze the codebase and generate initial recipes',
            '2. Use `alembic_search` to query knowledge while coding',
            '3. Run `alembic_guard` before committing to check compliance',
        ];
        return `${lines.join('\n')}\n`;
    }
    _ensureDir() {
        if (this.wz) {
            this.wz.ensureDir(this.wz.project(getCursorRulesRelativePath()));
        }
        else if (!fs.existsSync(this.rulesDir)) {
            fs.mkdirSync(this.rulesDir, { recursive: true });
        }
    }
}
export default RulesGenerator;
